SELECT count(*) FROM payment

    AND order_id = #{orderId}
    AND customer_id = #{customerId}
    AND payment_method = #{paymentMethod}
    AND state_id = #{stateId}

SELECT id as "id", order_id as "orderId", customer_id as "customerId", amount as "amount", currency as "currency", payment_method as "paymentMethod", gateway_transaction_id as "gatewayTransactionId", retry_count as "retryCount", failure_reason as "failureReason", state_id as "stateId", flow_id as "flowId", created_time as "createdTime" FROM payment
AND order_id = #{orderId} AND customer_id = #{customerId} AND payment_method = #{paymentMethod} AND state_id = #{stateId}
${orderby} ${pagination}

SELECT count(*) FROM payment_refunds

    AND payment_id = #{paymentId}
    AND status = #{status}

SELECT id as "id", payment_id as "paymentId", amount as "amount", reason as "reason", status as "status", created_time as "createdTime" FROM payment_refunds
AND payment_id = #{paymentId} AND status = #{status}
${orderby} ${pagination}

SELECT count(*) FROM payment_webhook_log

    AND payment_id = #{paymentId}
    AND event_type = #{eventType}
    AND provider = #{provider}
    AND status = #{status}

SELECT
    id as "id",
    payment_id as "paymentId",
    event_type as "eventType",
    provider as "provider",
    status as "status",
    created_time as "createdTime"
FROM payment_webhook_log

    AND payment_id = #{paymentId}
    AND event_type = #{eventType}
    AND provider = #{provider}
    AND status = #{status}

${orderby} ${pagination}
